[ApiController]
[Route("[controller]")]
public class ProductController : ControllerBase
{
    [HttpGet]
    public ActionResult<IEnumerable<Product>> GetAll()
    {
        return Ok(_productRepository.GetAll());
    }

    [HttpGet("{id:int}")]
    public ActionResult<Product> GetOne(int id)
    {
        var product = _productRepository.GetById(id);
        return product is null ? NotFound() : Ok(product);
    }
}

app.MapGet("/product", (IProductRepository productRepository) =>
{
    var products = productRepository.GetAll();
    return products.Any()
        ? Results.Ok(products)
        : Results.NoContent();
});

app.MapPost("/product", (Product product, IProductRepository productRepository) =>
{
    productRepository.Add(product);
    return Results.Created($"/product/{product.Id}", product);
});

service Products {
  rpc GetAll (AllProductsRequest) returns (AllProductsResponse);
  rpc CreateNew (CreateNewRequest) returns (CreateNewResponse);
}

